class Solution:
    def searchInsert(self, nums: list[int], target: int) -> int:
        l, r = 0, len(nums)          # 左闭右开 [l, r),所以 r 取 len(nums)
        while l < r:
            m = (l + r) // 2
            if nums[m] < target:     # m 处偏小 -> 答案在右边
                l = m + 1
            else:                    # m >= target -> 答案在 m 或更左
                r = m
        return l                     # l 即第一个 >= target 的位置(插入点)
